public static List<Integer> helper(int k){
        int curr =1;
        List<Integer> res = new ArrayList<>();
        res.add(curr);
        if(k==1) {
            return res;
        }
        int n=0;
        while(Math.pow(2,(n+1)) <= k){
            System.out.println("entered");
            List<Integer> newres = new ArrayList<>();
            int index=0;
            while(index<res.size()){
                System.out.println("res index"+ res.get(index));
                newres.add(res.get(index++));

                newres.add(++curr);
                 System.out.println("curr"+ curr);
            }
            res=new ArrayList<>(newres);
            n++;

        }
        res.add(++curr);

        int temp = res.get(1);
        res.set(1, res.get(res.size()-1));
        res.set(res.size()-1, temp);
        return res;
    }

O(n*log(n))
